        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[OpraDatabaseTradesRequestMessage](sbeTemplateId=");
            builder.Append(OpraDatabaseTradesRequestMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(OpraDatabaseTradesRequestMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != OpraDatabaseTradesRequestMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(OpraDatabaseTradesRequestMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != OpraDatabaseTradesRequestMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(OpraDatabaseTradesRequestMessage.BlockLength);
            builder.Append("):");

            builder.Append("RequestId=");
            builder.Append(this.RequestId);
            builder.Append('|');
            builder.Append("RequestSpreads=");
            builder.Append(this.RequestSpreads);
            builder.Append('|');
            builder.Append("RealTime=");
            builder.Append(this.RealTime);
            builder.Append('|');
            builder.Append("IsStopRequest=");
            builder.Append(this.IsStopRequest);
            builder.Append('|');
            builder.Append("StartTime=");
            builder.Append(this.StartTime);
            builder.Append('|');
            builder.Append("EndTime=");
            builder.Append(this.EndTime);
            builder.Append('|');
            builder.Append("DeltaAdjEdgeIntervalSeconds=");
            builder.Append(this.DeltaAdjEdgeIntervalSeconds);
            builder.Append('|');
            builder.Append("MatchIoiTrades=");
            builder.Append(this.MatchIoiTrades);
            builder.Append('|');
            builder.Append("Symbols=[");
            var symbols = this.Symbols;
            if (symbols.Count > 0)
            {
                var first = true;
                while (symbols.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    symbols.Next().BuildString(builder);
                }
            }
            builder.Append("]");
            builder.Append('|');
            builder.Append("UnderlyingSymbols=[");
            var underlyingSymbols = this.UnderlyingSymbols;
            if (underlyingSymbols.Count > 0)
            {
                var first = true;
                while (underlyingSymbols.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    underlyingSymbols.Next().BuildString(builder);
                }
            }
            builder.Append("]");
            builder.Append('|');
            builder.Append("Constraint1=");
            builder.Append('\'').Append(GetConstraint1()).Append('\'');
            builder.Append('|');
            builder.Append("Constraint2=");
            builder.Append('\'').Append(GetConstraint2()).Append('\'');

            this.Limit = originalLimit;

        }
